const results = [];

for (const item of $input.all()) {
  const event = item.json;

  // Only pick surgery events
  if (!event.summary || !event.summary.toLowerCase().includes('surgery')) {
    continue;
  }

  // Description is HTML-like, clean it
  const rawDesc = event.description || '';

  const cleanText = rawDesc
    .replace(/<[^>]*>/g, '')  // remove HTML tags
    .replace(/\s+/g, ' ')     // normalize spaces
    .trim();

  // Extract fields using regex
  const getValue = (key) => {
    const match = cleanText.match(new RegExp(`${key}:\\s*([^\\s]+[^:]*)`, 'i'));
    return match ? match[1].trim() : null;
  };

  const patient_name = getValue('patient_name');
  const patient_email = getValue('patient_email');
  const patient_phone = getValue('patient_phone');
  const patient_id = getValue('patient_id');
  const procedure = getValue('procedure');

  results.push({
    json: {
      event_id: event.id,
      surgery_time: event.start?.dateTime,
      patient_name,
      patient_email,
      patient_phone,
      patient_id,
      procedure,
      calendar_link: event.htmlLink
    }
  });
}

return results;

const allItems = $input.all();
let output = [];

allItems.forEach((item, index) => {
  const patient = item.json;

  const patientId = patient.patient_id;
  const uniqueId = `confirm_${patientId}_${Date.now()}_${index}`;

  output.push({
    json: {
      ...patient,
      uniqueId,
      confirmUrl: `https://n8n.tdwebsites.in/webhook-test/confirm?patient_id=${patientId}&uniqueId=${uniqueId}`,
      createdAt: new Date().toISOString()
    }
  });
});

return output;

const allItems = $input.all();

const output = allItems.map(item => {
  const data = item.json;

  return {
    json: {
      ...data,
      // Clean fields if they already exist
      patient_name: data.patient_name?.replace(' patient_email', ''),
      patient_email: data.patient_email?.replace(' patient_phone', ''),
      patient_phone: data.patient_phone?.replace(' patient_id', ''),
      patient_id: data.patient_id?.replace(' procedure', ''),
    }
  };
});

return output;

const items = $input.all();

// Simple in-memory store (for demo purposes)
const confirmations = [];

items.forEach(item => {
  const query = item.json.query || {};

  const patientIdRaw = query.patient_id || null;
  const uniqueIdRaw = query.uniqueId || null;

  // Clean messy values (remove extra words if present)
  const patient_id = patientIdRaw ? patientIdRaw.replace(' procedure', '').trim() : null;
  const uniqueId = uniqueIdRaw ? uniqueIdRaw.replace(' procedure', '').trim() : null;

  confirmations.push({
    patient_id,
    uniqueId,
    confirmed: true,
    confirmedAt: new Date().toISOString()
  });
});

// Return as items so next nodes can use it
return confirmations.map(c => ({
  json: c
}));

